const RARITIES = ["Comum","Incomum","Raro","Holo Raro","Ultra Raro","Secret Rare","Full Art","Alt Art","Special Illustration Rare"];
const EMOJIS = ["⚡","🔥","💎","🌙","🌊","🌿","🎴","🏆","✨","🎯"];
const LOGO = "data:image/png;base64,";

const fmt = v => `R$ ${Number(v).toLocaleString("pt-BR",{minimumFractionDigits:2})}`;
const nowTime = () => new Date().toLocaleTimeString("pt-BR",{hour:"2-digit",minute:"2-digit",second:"2-digit"});

const C = {
  bg:"#0A0A0F", panel:"#12101A", panelBorder:"#2D1F6E",
  purple:"#7B2FBE", purpleLight:"#A855F7", purpleDim:"#4C1D95",
  gold:"#F5A623", goldLight:"#FFD700",
  white:"#F0EEFF", gray:"#6B6880", grayLight:"#9B98AB",
  live:"#9333EA", danger:"#EF4444",
};

function ApexLogo({size=48}){ return <img src={LOGO} width={size} height={size} style={{objectFit:"contain"}}/>; }

function useToasts() {
  const [toasts,setToasts] = useState([]);
  const add = useCallback((msg,type="info")=>{
    const id = Date.now();
    setToasts(t=>[...t,{id,msg,type}]);
    setTimeout(()=>setToasts(t=>t.filter(x=>x.id!==id)),3500);
  },[]);
  return {toasts,add};
}

function useUsername() {
  const [username,setUsername] = useState(()=>localStorage.getItem("apex_username")||"");
  const save = name => { localStorage.setItem("apex_username",name); setUsername(name); };
  return [username,save];
}

export default function App() {
  const [view,setView] = useState("rooms");
  const [rooms,setRooms] = useState({});
  const [activeId,setActiveId] = useState(null);
  const [showNew,setShowNew] = useState(false);
  const [showAdminAuth,setShowAdminAuth] = useState(false);
  const [username,setUsername] = useUsername();
  const [showLogin,setShowLogin] = useState(!username);
  const {toasts,add:addToast} = useToasts();

  useEffect(()=>{
    const unsub = onValue(ref(db,"rooms"),snap=>setRooms(snap.val()||{}));
    return ()=>unsub();
  },[]);

  useEffect(()=>{
    if(view!=="room"||!activeId||!username) return;
    const room = rooms[activeId];
    if(!room||room.status!=="live"||room.owner!==username) return;
    const t = setInterval(async()=>{
      const r = rooms[activeId];
      if(!r||r.status!=="live") return;
      const tl = (r.timeLeft||0)-1;
      if(tl<=0) await update(ref(db,`rooms/${activeId}`),{timeLeft:0,status:"ended"});
      else await update(ref(db,`rooms/${activeId}`),{timeLeft:tl});
    },1000);
    return ()=>clearInterval(t);
  },[view,activeId,rooms,username]);

  const openRoom = id=>{setActiveId(id);setView("room");};
  const goRooms = ()=>{setView("rooms");setActiveId(null);};

  const createRoom = async data=>{
    let imageUrl = null;
    if(data.imageFile){
      try{
        addToast("Fazendo upload da foto...","info");
        const fileRef = sRef(storage,`cards/${Date.now()}_${data.imageFile.name}`);
        await uploadBytes(fileRef,data.imageFile);
        imageUrl = await getDownloadURL(fileRef);
      }catch(e){ addToast("Erro no upload, continuando sem foto","error"); }
    }
    const sp = parseFloat(data.startPrice)||100;
    const newRef = push(ref(db,"rooms"));
    await set(newRef,{
      name:data.name, emoji:data.emoji, status:"live",
      card:{name:data.cardName,set:data.cardSet,rarity:data.rarity,condition:data.condition,emoji:data.emoji,imageUrl},
      currentBid:sp, minIncrement:parseFloat(data.minIncrement)||50,
      timeLeft:parseInt(data.duration)||120,
      owner:username, createdAt:serverTimestamp(), history:{}
    });
    setShowNew(false);
    addToast("Sala criada! Boa sorte nos lances 🏆","success");
    openRoom(newRef.key);
  };

  const placeBid = async(roomId,amount)=>{
    const room = rooms[roomId];
    if(!room||room.status!=="live") return;
    if(amount<=room.currentBid){ addToast(`Lance mínimo: ${fmt(room.currentBid+room.minIncrement)}`,"error"); return; }
    const newTime = (room.timeLeft||0)<15?15:room.timeLeft;
    await update(ref(db,`rooms/${roomId}`),{currentBid:amount,currentBidder:username,timeLeft:newTime});
    await push(ref(db,`rooms/${roomId}/history`),{user:username,amount,time:nowTime(),ts:serverTimestamp()});
    addToast(`Lance de ${fmt(amount)} registrado! ⚡`,"success");
  };

  const roomList = Object.entries(rooms).map(([id,r])=>({...r,id})).sort((a,b)=>(b.createdAt||0)-(a.createdAt||0));
  const room = activeId?{...(rooms[activeId]||{}),id:activeId}:null;

  const globalStyle = `
    @import url('https://fonts.googleapis.com/css2?family=Cinzel:wght@700;900&family=Inter:wght@400;500;600;700&display=swap');
    *{box-sizing:border-box;margin:0;padding:0}
    body{background:#0A0A0F;color:#F0EEFF;font-family:'Inter',sans-serif}
    @keyframes float{0%,100%{transform:translateY(0)}50%{transform:translateY(-10px)}}
    @keyframes urgentPulse{0%,100%{color:#EF4444;transform:scale(1)}50%{color:#FF6B6B;transform:scale(1.06)}}
    @keyframes slideIn{from{transform:translateX(60px);opacity:0}to{transform:translateX(0);opacity:1}}
    @keyframes shimmerBar{0%,100%{opacity:.7}50%{opacity:1}}
    @keyframes blink{0%,100%{opacity:1}50%{opacity:.2}}
    .card-float{animation:float 3.5s ease-in-out infinite}
    .urgent-timer{animation:urgentPulse .6s ease-in-out infinite}
    .live-dot{display:inline-block;width:7px;height:7px;border-radius:50%;background:#9333EA;animation:blink 1.2s infinite;margin-right:6px;vertical-align:middle}
    .room-card{transition:all .25s;cursor:pointer}
    .room-card:hover{transform:translateY(-3px)!important;border-color:#A855F7!important;box-shadow:0 12px 40px #A855F733!important}
    .bid-btn-main:hover{filter:brightness(1.15);transform:scale(1.02)}
    .quick-bid:hover{background:#4C1D95!important;border-color:#A855F7!important;color:#F0EEFF!important}
    input:focus,select:focus{outline:none;border-color:#F5A623!important}
    input[type=number]::-webkit-inner-spin-button{opacity:1}
    ::-webkit-scrollbar{width:4px}::-webkit-scrollbar-track{background:#0A0A0F}
    ::-webkit-scrollbar-thumb{background:#4C1D95;border-radius:4px}
    @media(max-width:768px){.room-layout{grid-template-columns:1fr!important}}
  `;

  if(showLogin) return (
    <>
      <style>{globalStyle}</style>
      <LoginScreen onLogin={name=>{setUsername(name);setShowLogin(false);}}/>
    </>
  );

  return (
    <>
      <style>{globalStyle}</style>
      <div style={{minHeight:"100vh",background:C.bg,display:"flex",flexDirection:"column"}}>
        <header style={{background:"linear-gradient(180deg,#1A0A3E,#0D0820)",borderBottom:`1px solid ${C.panelBorder}`,padding:"0 24px",height:64,display:"flex",alignItems:"center",gap:14,position:"sticky",top:0,zIndex:100,boxShadow:"0 4px 24px #000C"}}>
          <div style={{display:"flex",alignItems:"center",gap:8,cursor:"pointer"}} onClick={goRooms}>
            <ApexLogo size={52}/>
            <span style={{fontSize:10,color:C.gray,letterSpacing:2,textTransform:"uppercase"}}>Leilão ao vivo</span>
          </div>
          <nav style={{display:"flex",gap:4,marginLeft:20}}>
            {[["rooms","⚡ Salas"],["catalog","📋 Histórico"]].map(([v,l])=>(
              <button key={v} onClick={()=>v==="rooms"?goRooms():setView(v)}
                style={{background:view===v?"linear-gradient(135deg,#2D1F6E,#3B0F80)":"transparent",border:`1px solid ${view===v?C.purpleLight:C.panelBorder}`,borderRadius:8,padding:"6px 16px",fontSize:12,fontWeight:600,color:view===v?C.white:C.gray,cursor:"pointer"}}>
                {l}
              </button>
            ))}
          </nav>
          <div style={{marginLeft:"auto",display:"flex",alignItems:"center",gap:10}}>
            <div style={{background:"linear-gradient(135deg,#1A0A3E,#2D1F6E)",border:`1px solid ${C.purpleLight}`,borderRadius:20,padding:"6px 16px",fontSize:13,fontWeight:600,color:C.purpleLight,display:"flex",alignItems:"center",gap:6}}>
              👤 {username}
            </div>
            <button onClick={()=>setShowLogin(true)} style={{background:"transparent",border:`1px solid ${C.panelBorder}`,borderRadius:8,padding:"6px 10px",fontSize:11,color:C.gray,cursor:"pointer"}}>Trocar</button>
          </div>
        </header>

        <main style={{flex:1,padding:24,maxWidth:1400,margin:"0 auto",width:"100%"}}>
          {view==="rooms"&&<RoomsView rooms={roomList} onOpen={openRoom} onNew={()=>setShowAdminAuth(true)}/>}
          {view==="room"&&room&&<RoomView room={room} myUser={username} onBack={goRooms} onBid={placeBid}/>}
          {view==="catalog"&&<CatalogView rooms={roomList}/>}
        </main>
      </div>

      {showAdminAuth&&(
        <AdminAuthModal
          onClose={()=>setShowAdminAuth(false)}
          onSuccess={()=>{setShowAdminAuth(false);setShowNew(true);}}
        />
      )}
      {showNew&&<NewRoomModal onClose={()=>setShowNew(false)} onCreate={createRoom}/>}

      <div style={{position:"fixed",top:74,right:20,zIndex:999,display:"flex",flexDirection:"column",gap:8,pointerEvents:"none"}}>
        {toasts.map(t=>(
          <div key={t.id} style={{background:t.type==="success"?"linear-gradient(135deg,#1A0A3E,#2D1F6E)":t.type==="error"?"#1A0010":"#1A0A3E",border:`1px solid ${t.type==="success"?C.purpleLight:t.type==="error"?C.danger:C.panelBorder}`,borderLeft:`3px solid ${t.type==="success"?C.gold:t.type==="error"?C.danger:C.purpleLight}`,borderRadius:10,padding:"12px 18px",fontSize:13,fontWeight:600,color:C.white,animation:"slideIn .3s ease",maxWidth:300,boxShadow:"0 8px 32px #000A"}}>
            {t.msg}
          </div>
        ))}
      </div>
    </>
  );
}

function AdminAuthModal({onClose,onSuccess}){
  const [pass,setPass] = useState("");
  const [err,setErr] = useState(false);
  const check = ()=>{
    if(pass===ADMIN_PASS){ onSuccess(); }
    else{ setErr(true); setTimeout(()=>setErr(false),2000); }
  };
  return (
    <div onClick={e=>e.target===e.currentTarget&&onClose()} style={{position:"fixed",inset:0,background:"#000000CC",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:20}}>
      <div style={{background:"linear-gradient(160deg,#12101A,#0D0820)",border:`1px solid ${err?C.danger:C.panelBorder}`,borderRadius:18,padding:32,width:"100%",maxWidth:360,textAlign:"center",boxShadow:"0 24px 80px #000C",transition:"border-color .3s"}}>
        <div style={{fontSize:40,marginBottom:12}}>🔐</div>
        <div style={{fontFamily:"'Cinzel',serif",fontSize:18,fontWeight:900,background:"linear-gradient(90deg,#FFD700,#F5A623)",WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",marginBottom:8}}>Área do Admin</div>
        <div style={{fontSize:13,color:C.gray,marginBottom:24}}>Digite a senha para criar uma sala</div>
        <input type="password" placeholder="••••••••" value={pass}
          onChange={e=>setPass(e.target.value)}
          onKeyDown={e=>e.key==="Enter"&&check()}
          style={{width:"100%",background:"#0A0A0F",border:`1px solid ${err?C.danger:C.panelBorder}`,borderRadius:10,padding:"12px 16px",color:C.white,fontSize:18,marginBottom:err?8:16,textAlign:"center",letterSpacing:6}}/>
        {err&&<div style={{color:C.danger,fontSize:12,marginBottom:12,fontWeight:600}}>Senha incorreta!</div>}
        <div style={{display:"flex",gap:10}}>
          <button onClick={onClose} style={{flex:1,background:"transparent",border:`1px solid ${C.panelBorder}`,borderRadius:8,padding:"11px",color:C.gray,fontSize:14,cursor:"pointer"}}>Cancelar</button>
          <button onClick={check} style={{flex:1,background:`linear-gradient(135deg,${C.purple},${C.purpleDim})`,border:`1px solid ${C.purpleLight}`,borderRadius:8,padding:"11px",color:C.white,fontWeight:700,fontSize:14,cursor:"pointer"}}>Entrar</button>
        </div>
      </div>
    </div>
  );
}

